UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('IO', 'JUC', 'JVM', 'JVM相关', 'Java', 'Java 8', 'Java IO/NIO/AIO', 'Java 基础', 'Java 多线程与并发', 'Java 新版本', 'Java 集合框架', 'Java8 以上特性概述', 'Java8 特性详解', 'Java其它相关', 'Linux', 'SPI', '反射', '并发编程', '异常', '泛型', '注解', '源码解析', '算法', '线程池', '设计模式', '集合框架', '面向对象');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200001);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9301001, 9301002, 9301003, 9301004, 9301005, 9301006, 9301007, 9301008);

